// Each problem: { id, title, category, difficulty, description, examples,
//                 starterCode, testCases:[{args, expected}], testRunner }
// testRunner runs the user's function against testCases and reports pass/fail.

function RUN(fn) {
  return this.testCases.map(tc => {
    let got, pass;
    try {
      got = fn(...tc.args);
      pass = JSON.stringify(got) === JSON.stringify(tc.expected);
    } catch (e) {
      got = "Error: " + e.message;
      pass = false;
    }
    return {
      input: JSON.stringify(tc.args),
      expected: JSON.stringify(tc.expected),
      got: JSON.stringify(got),
      pass
    };
  });
}

